sql:
SELECT name
FROM neighborhoods
ORDER BY median_income DESC;

SELECT age_group, count, percentage, last_updated, age_id, population_id
FROM age_distributions
WHERE age_id = 1;

SELECT median_income
FROM neighborhoods
WHERE last_updated = (
  SELECT MAX(last_updated)
  FROM neighborhoods
);

SELECT education_level, count, percentage
FROM education_data
WHERE education_id = 0;

SELECT age_group, SUM(count) as total_count
FROM age_distributions
GROUP BY age_group;
